import{_ as e,c as a,o as s,aN as d}from"./chunks/framework.CqA5BTDU.js";const i="/kb/assets/zabbix-host-edit-node13-clean-annotated.C8ZNPO6d.png",o="/kb/assets/zabbix-latest-data-lab-custom-pagedown-annotated.9iWkZBIX.png",n="/kb/assets/zabbix-dashboard-lab-custom-metrics-annotated.DwhVXXkP.png",p="/kb/assets/zabbix-trigger-list-lab-annotated.D-FugqTs.png",c="/kb/assets/zabbix-problem-lab-app-health-resolved-annotated.D7mfk73k.png",l="/kb/assets/zabbix-action-list-lab-app-health-annotated.DeDeAkrx.png",r="/kb/assets/zabbix-action-log-lab-large-annotated.PDZoULXs.png",x=JSON.parse('{"title":"Zabbix平台操作","description":"","frontmatter":{},"headers":[],"relativePath":"12.可观测性与监控告警/24-Zabbix平台操作.md","filePath":"12.可观测性与监控告警/24-Zabbix平台操作.md","lastUpdated":null}'),h={name:"12.可观测性与监控告警/24-Zabbix平台操作.md"};function b(g,t,k,m,F,A){return s(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="zabbix平台操作" tabindex="-1">Zabbix平台操作 <a class="header-anchor" href="#zabbix平台操作" aria-label="Permalink to &quot;Zabbix平台操作&quot;">​</a></h1><p>Zabbix 控制台操作通常沿着一条固定链路展开：主机接入、监控项定义、最近值验证、图形或 Dashboard 展示、触发器生成事件、Action 执行通知。平台页面很多，排查时关键是理清对象之间的连接关系：Host 绑定哪个 Interface，Item 的 key 从哪里来，Latest data 有没有真实值，Trigger 表达式命中后 Action 有没有留下发送记录。</p><p>当前实验环境：</p><table tabindex="0"><thead><tr><th>角色</th><th>地址</th><th>说明</th></tr></thead><tbody><tr><td>Zabbix Server / Web / DB</td><td><code>192.168.10.11</code></td><td>Server、Web、MariaDB、Agent2</td></tr><tr><td>被监控节点</td><td><code>192.168.10.12</code></td><td>Linux Agent2</td></tr><tr><td>被监控节点</td><td><code>192.168.10.13</code></td><td>Linux Agent2，自定义指标实验节点</td></tr></tbody></table><h2 id="一、对象关系" tabindex="-1">一、对象关系 <a class="header-anchor" href="#一、对象关系" aria-label="Permalink to &quot;一、对象关系&quot;">​</a></h2><p>Zabbix 里的平台对象有层级关系。Host 是被监控对象，Interface 是采集入口，Item 是具体采什么数据，Trigger 是把数据变成问题事件的规则，Action 是事件发生后要执行的通知或脚本动作。</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20%20%20host%5B%22Host%3Cbr%2F%3Ezbx-node13%22%5D%20--%3E%20iface%5B%22Agent%20interface%3Cbr%2F%3E192.168.10.13%3A10050%22%5D%0A%20%20%20%20host%20--%3E%20item%5B%22Item%3Cbr%2F%3Elab.proc.count%20%2F%20lab.app.health%22%5D%0A%20%20%20%20item%20--%3E%20latest%5B%22Latest%20data%3Cbr%2F%3E%E6%9C%80%E8%BF%91%E9%87%87%E9%9B%86%E5%80%BC%22%5D%0A%20%20%20%20item%20--%3E%20view_node%5B%22Graph%20%2F%20Dashboard%3Cbr%2F%3E%E8%B6%8B%E5%8A%BF%E5%9B%BE%E5%92%8C%E5%80%BC%E9%9D%A2%E6%9D%BF%22%5D%0A%20%20%20%20item%20--%3E%20trigger%5B%22Trigger%3Cbr%2F%3Elast(...)%3D0%22%5D%0A%20%20%20%20trigger%20--%3E%20problem%5B%22Problem%20%2F%20Event%3Cbr%2F%3E%E5%8F%91%E7%94%9F%E4%B8%8E%E6%81%A2%E5%A4%8D%E8%AE%B0%E5%BD%95%22%5D%0A%20%20%20%20problem%20--%3E%20action%5B%22Action%20log%3Cbr%2F%3E%E9%80%9A%E7%9F%A5%E5%8A%A8%E4%BD%9C%E4%B8%8E%E5%A4%B1%E8%B4%A5%E5%8E%9F%E5%9B%A0%22%5D%0A"></div><p>对象之间的关系直接影响排错顺序。Agent 命令能返回值，只说明被监控机本地或 Server 到 Agent 的链路通了；Latest data 出现最近值，才说明 Zabbix 的 Item 已经把数据收进平台；Trigger 生成 Problem，才说明告警规则真的参与了事件处理。</p><h2 id="二、主机接入" tabindex="-1">二、主机接入 <a class="header-anchor" href="#二、主机接入" aria-label="Permalink to &quot;二、主机接入&quot;">​</a></h2><p>Linux Agent 被接入平台时，主机页最关键的是 Host name、Host groups、Templates 和 Agent interface。Host name 是平台内部识别名，主动模式下还会和 Agent 配置里的 <code>Hostname=</code> 对齐；Visible name 只是展示名，通常会带 IP，方便在列表和告警里辨认。</p><p>操作路径：</p><p><code>Data collection -&gt; Hosts -&gt; Create host</code> （中文：数据采集 -&gt; 主机 -&gt; 创建主机）</p><p>操作步骤：</p><ol><li>进入 <code>Data collection -&gt; Hosts</code>，点击右上角 <code>Create host</code>。</li><li>在 <code>Host</code> 页填写 <code>Host name</code>、<code>Visible name</code> 和 <code>Host groups</code>。</li><li>在 <code>Interfaces</code> 区域添加 <code>Agent</code> 接口，填写被监控机 IP 和端口。</li><li>在 <code>Templates</code> 区域选择 <code>Linux by Zabbix agent</code>。</li><li>点击 <code>Add</code> 保存主机。</li></ol><table tabindex="0"><thead><tr><th>字段</th><th>当前值</th><th>作用</th></tr></thead><tbody><tr><td>Host name</td><td><code>zbx-node13</code></td><td>平台内部主机名</td></tr><tr><td>Visible name</td><td><code>zbx-node13 192.168.10.13</code></td><td>页面展示名</td></tr><tr><td>Host groups</td><td><code>Linux lab</code></td><td>分组、权限、筛选和 Action 条件都可能用到</td></tr><tr><td>Templates</td><td><code>Linux by Zabbix agent</code></td><td>模板提供 Linux 基础监控项和触发器</td></tr><tr><td>Agent interface</td><td><code>192.168.10.13:10050</code></td><td>Server 访问 Agent 的入口</td></tr></tbody></table><p><img src="'+i+`" alt="Zabbix主机接入字段"></p><p>保存后验证：</p><p><code>Data collection -&gt; Hosts</code> （中文：数据采集 -&gt; 主机）</p><p>主机列表里 <code>zbx-node13</code> 的 <code>ZBX</code> 状态变绿，表示 Zabbix Server 能通过 Agent 接口通信。更直接的验证方式是进入 <code>Monitoring -&gt; Latest data</code>（中文：监控 -&gt; 最新数据）筛选 <code>zbx-node13</code>，确认模板 Item 已经有最近值。</p><p>排错入口：</p><p><code>Data collection -&gt; Hosts -&gt; zbx-node13 -&gt; Interfaces</code> （中文：数据采集 -&gt; 主机 -&gt; zbx-node13 -&gt; 接口）</p><p>这里检查 IP、端口和接口类型。页面仍不绿时，在 Server 上用 <code>zabbix_get</code> 验证 10050 端口和 Agent key；Agent 日志里再看 <code>Server=</code>、<code>Hostname=</code>、防火墙和 SELinux 相关问题。</p><p>Server 侧可以直接用 <code>zabbix_get</code> 验证 Agent 链路。这个命令绕过 Web 页面过滤条件，适合确认&quot;Server 到 Agent 是否真的能取值&quot;。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 在 Zabbix Server 上执行，确认 192.168.10.13 的 Agent 有响应</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zabbix_get</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.13</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -k</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> agent.ping</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看 Agent 返回的主机名，主动模式排错时经常会用到</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zabbix_get</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.13</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -k</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> system.hostname</span></span></code></pre></div><p>当前返回值：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1</span></span>
<span class="line"><span>zbx-node13</span></span></code></pre></div><p><code>agent.ping=1</code> 表示 Agent 通信正常。这个结果还不能代表业务指标正常，只能说明 Agent 入口可用。</p><h2 id="三、自定义指标" tabindex="-1">三、自定义指标 <a class="header-anchor" href="#三、自定义指标" aria-label="Permalink to &quot;三、自定义指标&quot;">​</a></h2><p>模板能覆盖 CPU、内存、磁盘、进程等常见指标，但业务健康状态、脚本检查结果、特殊端口状态通常需要自定义 Item。Zabbix Agent2 侧可以通过 <code>UserParameter</code> 暴露自定义 key，Server 再用 Item 去采集这个 key。</p><p><code>zbx-node13</code> 上的实验配置：</p><div class="language-ini vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># /etc/zabbix/zabbix_agent2.d/lab-userparameter.conf</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 当前系统进程数量，用于演示普通数值型自定义指标</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">UserParameter</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=lab.proc.count,ps -e --no-headers | wc -l</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 用文件模拟应用健康状态：1 表示正常，0 表示异常</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">UserParameter</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=lab.app.health,cat /tmp/lab_app_health 2&gt;/dev/null || echo 1</span></span></code></pre></div><p>修改 Agent 配置后重启服务：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 初始化健康状态文件，避免第一次采集返回空值</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">printf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;1\\n&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/tmp/lab_app_health</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 重新加载 Agent2 配置文件</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> zabbix-agent2</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 确认 Agent2 正常运行，10050 端口处于监听状态</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> is-active</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> zabbix-agent2</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ss</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lntp</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;:10050\\b&#39;</span></span></code></pre></div><p>Server 侧直接验证自定义 key：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 直接读取进程数量，返回值应为一个整数</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zabbix_get</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.13</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -k</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lab.proc.count</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 直接读取应用健康状态，正常状态返回 1</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zabbix_get</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.13</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -k</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lab.app.health</span></span></code></pre></div><p>当前返回值类似：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>187</span></span>
<span class="line"><span>1</span></span></code></pre></div><p>平台侧创建 Item 时，字段要和 Agent key 对齐：</p><p>操作路径：</p><p><code>Data collection -&gt; Hosts -&gt; zbx-node13 -&gt; Items -&gt; Create item</code> （中文：数据采集 -&gt; 主机 -&gt; zbx-node13 -&gt; 监控项 -&gt; 创建监控项）</p><p>操作步骤：</p><ol><li>进入 <code>Data collection -&gt; Hosts</code>，点击 <code>zbx-node13</code>。</li><li>打开 <code>Items</code>，点击 <code>Create item</code>。</li><li>创建 <code>Lab process count</code>，<code>Key</code> 填 <code>lab.proc.count</code>。</li><li>再创建 <code>Lab application health</code>，<code>Key</code> 填 <code>lab.app.health</code>。</li><li>两个 Item 都选择 <code>Zabbix agent</code> 类型，信息类型选择 <code>Numeric (unsigned)</code>。</li><li>点击 <code>Add</code> 保存。</li></ol><table tabindex="0"><thead><tr><th>字段</th><th><code>Lab process count</code></th><th><code>Lab application health</code></th><th>说明</th></tr></thead><tbody><tr><td>Type</td><td><code>Zabbix agent</code></td><td><code>Zabbix agent</code></td><td>Server 通过 Agent 被动采集</td></tr><tr><td>Key</td><td><code>lab.proc.count</code></td><td><code>lab.app.health</code></td><td>和 <code>UserParameter</code> 的 key 保持一致</td></tr><tr><td>Type of information</td><td><code>Numeric (unsigned)</code></td><td><code>Numeric (unsigned)</code></td><td>两个值都是整数</td></tr><tr><td>Update interval</td><td><code>30s</code></td><td><code>30s</code></td><td>实验环境方便观察，生产环境按指标重要程度设置</td></tr><tr><td>History</td><td><code>7d</code></td><td><code>7d</code></td><td>原始值保留时间</td></tr><tr><td>Trends</td><td><code>30d</code></td><td><code>30d</code></td><td>趋势数据保留时间</td></tr><tr><td>Tags</td><td><code>scope=lab</code>, <code>component=custom</code></td><td><code>scope=lab</code>, <code>component=custom</code></td><td>方便筛选 Latest data、事件和 Action</td></tr></tbody></table><p>保存后验证：</p><p><code>Monitoring -&gt; Latest data</code> （中文：监控 -&gt; 最新数据）</p><p>筛选 <code>Host groups=Linux lab</code>、<code>Hosts=zbx-node13</code>，在 Name 里搜索 <code>Lab</code>。<code>Lab process count</code> 和 <code>Lab application health</code> 有 <code>Last check</code> 与 <code>Last value</code>，说明自定义 Item 已经进入平台采集链路。</p><p>Item 创建完以后，Latest data 是最直接的验证页面。图里能看到两个自定义指标已经有最近值，同时故意创建的 <code>Lab missing metric</code> 处于异常入口，适合记录自定义指标排错位置。</p><p>Latest data 的几个字段含义：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>Host</td><td>数据来自哪台主机</td></tr><tr><td>Name</td><td>Item 展示名</td></tr><tr><td>Last check</td><td>最近一次采集距离当前的时间</td></tr><tr><td>Last value</td><td>最近一次采集到的值</td></tr><tr><td>Tags</td><td>Item 标签，告警路由和筛选都会用到</td></tr><tr><td>Info</td><td>Item 异常原因入口，Not supported 时尤其重要</td></tr></tbody></table><p><img src="`+o+`" alt="Zabbix自定义指标最近值"></p><p>排错入口：</p><p><code>Data collection -&gt; Hosts -&gt; zbx-node13 -&gt; Items</code> （中文：数据采集 -&gt; 主机 -&gt; zbx-node13 -&gt; 监控项）</p><p>Item 变成 <code>Not supported</code> 时看 <code>Info</code> 列。<code>Unknown metric</code> 通常说明 Agent 侧没有加载对应 <code>UserParameter</code>；权限错误、脚本超时、返回值类型不匹配，也会在这里暴露。</p><p><code>Lab missing metric</code> 的错误原因是 <code>Unknown metric lab.missing.metric</code>。这种错误一般不是 Web 页面问题，而是 Agent 侧没有这个 key，或者 <code>UserParameter</code> 文件没有加载。修复顺序可以按下面走：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 在 Server 侧直接验证错误 key，确认 Agent 是否认识这个指标</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zabbix_get</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.13</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -k</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lab.missing.metric</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 在 Agent 节点确认自定义配置文件是否存在</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -R</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;lab.missing.metric&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/zabbix/zabbix_agent2.d/</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/zabbix/zabbix_agent2.conf</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 修改 UserParameter 后重启 Agent2，再回到 Latest data 等待下一轮采集</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> zabbix-agent2</span></span></code></pre></div><h2 id="四、图形与dashboard" tabindex="-1">四、图形与Dashboard <a class="header-anchor" href="#四、图形与dashboard" aria-label="Permalink to &quot;四、图形与Dashboard&quot;">​</a></h2><p>Latest data 能证明数据已经进平台，但日常值班更依赖图形和 Dashboard。图形关注趋势，Dashboard 把多个对象放到同一张视图里。当前实验 Dashboard 放了三块内容：进程数量趋势、应用健康值、当前问题列表。</p><p>图形创建路径：</p><p><code>Data collection -&gt; Hosts -&gt; zbx-node13 -&gt; Graphs -&gt; Create graph</code> （中文：数据采集 -&gt; 主机 -&gt; zbx-node13 -&gt; 图形 -&gt; 创建图形）</p><p>操作步骤：</p><ol><li>进入 <code>zbx-node13</code> 的 <code>Graphs</code> 页面，点击 <code>Create graph</code>。</li><li><code>Name</code> 填 <code>Lab process count trend</code>。</li><li>在 Items 里添加 <code>Lab process count</code>。</li><li>点击 <code>Add</code> 保存。</li></ol><p>Dashboard 配置路径：</p><p><code>Dashboards -&gt; Create dashboard / Edit dashboard -&gt; Add widget</code> （中文：仪表盘 -&gt; 创建/编辑仪表盘 -&gt; 添加组件）</p><p>字段填写：</p><table tabindex="0"><thead><tr><th>组件</th><th>类型</th><th>关键配置</th></tr></thead><tbody><tr><td><code>Lab process count trend</code></td><td>Graph</td><td>选择 Graph <code>Lab process count trend</code></td></tr><tr><td><code>Lab application health</code></td><td>Item value</td><td>Host 选 <code>zbx-node13</code>，Item 选 <code>Lab application health</code></td></tr><tr><td><code>Lab problems</code></td><td>Problems</td><td>过滤 <code>scope=lab</code> 或当前主机相关问题</td></tr></tbody></table><p>保存后验证：</p><p>打开对应 Dashboard，进程数量有趋势线，应用健康值显示 <code>1.00</code>，Problems 组件能在触发器命中后显示事件。Dashboard 没图时回 <code>Monitoring -&gt; Latest data</code> 确认 Item 先有值，再检查 Graph 或 Widget 绑定的 Item 是否正确。</p><p><img src="`+n+'" alt="Zabbix自定义指标Dashboard"></p><p>Dashboard 里这三个组件对应的关系：</p><table tabindex="0"><thead><tr><th>组件</th><th>数据来源</th><th>用途</th></tr></thead><tbody><tr><td><code>Lab process count trend</code></td><td>Graph <code>Lab process count trend</code></td><td>看进程数量是否突然上涨或下降</td></tr><tr><td><code>Lab application health</code></td><td>Item <code>Lab application health</code></td><td>直接展示当前健康值</td></tr><tr><td><code>Lab problems</code></td><td>Problems widget</td><td>查看当前未恢复的问题</td></tr></tbody></table><p>进程数量这种指标适合用趋势图。健康状态这种 0/1 指标适合用单值面板，值为 <code>1</code> 时表示正常，值为 <code>0</code> 时表示异常。Dashboard 里如果只放默认模板图，后续排查自定义指标时还要回 Latest data 重新筛选；把实验指标单独放出来，能直接看到它是否还在采集。</p><h2 id="五、触发器" tabindex="-1">五、触发器 <a class="header-anchor" href="#五、触发器" aria-label="Permalink to &quot;五、触发器&quot;">​</a></h2><p>Trigger 用来把 Item 的值转换成问题事件。当前实验的触发器为：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>last(/zbx-node13/lab.app.health)=0</span></span></code></pre></div><p>表达式含义是：<code>zbx-node13</code> 这台主机的 <code>lab.app.health</code> 最近一次值等于 <code>0</code> 时，触发问题。这个表达式适合演示业务健康状态，不依赖停止 Agent 服务，所以能区分&quot;Agent 掉线&quot;和&quot;应用状态异常&quot;。</p><p>操作路径：</p><p><code>Data collection -&gt; Hosts -&gt; zbx-node13 -&gt; Triggers -&gt; Create trigger</code> （中文：数据采集 -&gt; 主机 -&gt; zbx-node13 -&gt; 触发器 -&gt; 创建触发器）</p><p>操作步骤：</p><ol><li>进入 <code>zbx-node13</code> 的 <code>Triggers</code> 页面，点击 <code>Create trigger</code>。</li><li><code>Name</code> 填 <code>Lab application health is down</code>。</li><li><code>Expression</code> 填 <code>last(/zbx-node13/lab.app.health)=0</code>。</li><li><code>Severity</code> 选择 <code>High</code>。</li><li>添加标签 <code>scope=lab</code>、<code>component=app</code>、<code>node=zbx-node13</code>。</li><li>点击 <code>Add</code> 保存。</li></ol><p>保存后验证：</p><p><code>Data collection -&gt; Hosts -&gt; zbx-node13 -&gt; Triggers</code> （中文：数据采集 -&gt; 主机 -&gt; zbx-node13 -&gt; 触发器）</p><p>列表里能看到触发器名称、表达式、严重级别和标签。后续把 <code>lab.app.health</code> 改为 <code>0</code> 时，<code>Monitoring -&gt; Problems</code>（中文：监控 -&gt; 问题）会生成事件。</p><p>字段含义：</p><table tabindex="0"><thead><tr><th>字段</th><th>当前值</th><th>说明</th></tr></thead><tbody><tr><td>Name</td><td><code>Lab application health is down</code></td><td>问题名会出现在 Problems 和通知里</td></tr><tr><td>Expression</td><td><code>last(/zbx-node13/lab.app.health)=0</code></td><td>最近值为 0 时触发</td></tr><tr><td>Severity</td><td><code>High</code></td><td>告警级别，用于过滤和通知策略</td></tr><tr><td>Tags</td><td><code>scope=lab</code>, <code>component=app</code>, <code>node=zbx-node13</code></td><td>Action 匹配和事件筛选都会用到</td></tr><tr><td>Manual close</td><td>enabled</td><td>实验里允许手动关闭问题</td></tr></tbody></table><p><img src="'+p+`" alt="Zabbix触发器表达式"></p><p>排错入口：</p><p>触发器不出事件时，先看 <code>Monitoring -&gt; Latest data</code> 里的 <code>Lab application health</code> 最近值，再回触发器表达式确认 Host、Item key、函数和比较值。值类型不匹配、Item 没数据、表达式 host 名写错，都会导致规则看似存在但不触发。</p><p><code>last()</code> 只看最近一次值。实际生产里还会遇到抖动问题，比如健康检查偶发返回 0，下一次又恢复。类似场景通常会加持续时间或次数判断，例如用 <code>min(/host/key,3m)=0</code> 表示 3 分钟内最小值都是 0，告警会更稳。</p><h2 id="六、制造一次事件" tabindex="-1">六、制造一次事件 <a class="header-anchor" href="#六、制造一次事件" aria-label="Permalink to &quot;六、制造一次事件&quot;">​</a></h2><p><code>lab.app.health</code> 的值由 <code>/tmp/lab_app_health</code> 控制。把文件写成 <code>0</code>，Agent 下一次读取时就会返回异常值；恢复成 <code>1</code> 后，触发器会生成恢复事件。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 在 zbx-node13 上执行，模拟应用健康检查失败</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">printf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;0\\n&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/tmp/lab_app_health</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 从 Server 侧确认 Agent 已经返回异常值</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zabbix_get</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.13</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -k</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lab.app.health</span></span></code></pre></div><p>恢复：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 在 zbx-node13 上执行，恢复应用健康状态</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">printf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;1\\n&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/tmp/lab_app_health</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 从 Server 侧确认健康值已经恢复</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zabbix_get</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.13</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -k</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lab.app.health</span></span></code></pre></div><p>Problems 页面记录了这次事件。图里能看到发生时间、恢复时间、状态、问题名、持续时间和 Action 次数。<code>RESOLVED</code> 表示触发器已经从 Problem 状态恢复。</p><p>查看路径：</p><p><code>Monitoring -&gt; Problems</code> （中文：监控 -&gt; 问题）</p><p>操作步骤：</p><ol><li>进入 <code>Monitoring -&gt; Problems</code>。</li><li>筛选主机 <code>zbx-node13</code>，或按标签 <code>scope=lab</code> 过滤。</li><li>查看 <code>Lab application health is down</code> 的状态、发生时间、恢复时间和 Action 次数。</li><li>点击问题名称或事件详情，查看事件标签和恢复记录。</li></ol><p>验证重点：</p><table tabindex="0"><thead><tr><th>字段</th><th>作用</th></tr></thead><tbody><tr><td>Time</td><td>问题发生时间</td></tr><tr><td>Recovery time</td><td>恢复时间</td></tr><tr><td>Status</td><td>当前状态，常见为 <code>PROBLEM</code> 或 <code>RESOLVED</code></td></tr><tr><td>Host</td><td>影响对象</td></tr><tr><td>Problem</td><td>触发器名称</td></tr><tr><td>Duration</td><td>持续时间</td></tr><tr><td>Actions</td><td>事件关联的通知或动作次数</td></tr><tr><td>Tags</td><td>Action 匹配和后续筛选依据</td></tr></tbody></table><p><img src="`+c+'" alt="Zabbix自定义指标事件恢复"></p><p>同一台主机上 Agent 掉线和业务健康失败是两类问题。Agent 掉线通常表现为 <code>agent.ping</code>、<code>agent.available</code> 异常；业务健康失败则是自定义 key 返回异常值。复盘时把这两类写开，定位会更清楚。</p><h2 id="七、action与通知记录" tabindex="-1">七、Action与通知记录 <a class="header-anchor" href="#七、action与通知记录" aria-label="Permalink to &quot;七、Action与通知记录&quot;">​</a></h2><p>Action 负责把事件转成通知动作。它不是触发器本身，而是事件匹配规则。一个 Action 通常由 Conditions、Operations、Recovery operations 组成。</p><p>操作路径：</p><p><code>Alerts -&gt; Actions -&gt; Trigger actions -&gt; Create action</code> （中文：告警 -&gt; 动作 -&gt; 触发器动作 -&gt; 创建动作）</p><p>操作步骤：</p><ol><li>进入 <code>Alerts -&gt; Actions -&gt; Trigger actions</code>，点击 <code>Create action</code>。</li><li><code>Name</code> 填 <code>Lab app health action</code>。</li><li><code>Conditions</code> 里添加条件，匹配触发器 <code>Lab application health is down</code>。</li><li><code>Operations</code> 里添加发送消息给 <code>Admin</code>，媒介选择 <code>Lab script notification</code>。</li><li><code>Recovery operations</code> 里也添加发送消息给 <code>Admin</code>。</li><li>点击 <code>Add</code> 保存。</li></ol><p>保存后验证：</p><p><code>Alerts -&gt; Actions -&gt; Trigger actions</code> （中文：告警 -&gt; 动作 -&gt; 触发器动作）</p><p>列表里确认 Action 处于启用状态，条件、Operation 和 Recovery operation 都存在。再制造一次 <code>lab.app.health=0</code> 的事件，Action 次数会出现在 Problems 页面。</p><p>Action 字段关系：</p><table tabindex="0"><thead><tr><th>对象</th><th>当前值</th><th>说明</th></tr></thead><tbody><tr><td>Action</td><td><code>Lab app health action</code></td><td>告警动作名称</td></tr><tr><td>Condition</td><td>Trigger equals <code>Lab application health is down</code></td><td>只匹配这个实验触发器</td></tr><tr><td>Operation</td><td>Send message to <code>Admin</code></td><td>问题发生时发送</td></tr><tr><td>Recovery operation</td><td>Send message to <code>Admin</code></td><td>问题恢复时发送</td></tr><tr><td>Media type</td><td><code>Lab script notification</code></td><td>实验用脚本媒介</td></tr></tbody></table><p><img src="'+l+'" alt="Zabbix Action匹配条件"></p><p>Action 配好以后，还要看 Action log。事件出现但没有通知到人时，Action log 比 Action 列表更关键，因为它会说明有没有匹配到 Action、用了哪个媒介、发给谁、状态是什么。</p><p>查看路径：</p><p><code>Reports -&gt; Action log</code> （中文：报表 -&gt; 动作日志）</p><p>操作步骤：</p><ol><li>进入 <code>Reports -&gt; Action log</code>。</li><li>按时间范围筛选刚才制造的事件。</li><li>查看 <code>Action</code>、<code>Media type</code>、<code>Recipient</code>、<code>Status</code> 和 <code>Info</code>。</li><li><code>Status=Failed</code> 时点击或展开 <code>Info</code>，查看失败原因。</li></ol><p>排错入口：</p><p>Problems 有事件但 Action log 没记录，通常是 Action 条件没匹配、Action 未启用，或 Operation 没配置。Action log 有记录但失败，就看 <code>Info</code> 里的媒介、消息模板、用户 Media、脚本权限或外部通知接口错误。</p><p><img src="'+r+'" alt="Zabbix Action log发送记录"></p><p>当前实验里 Action log 有两条记录：一条对应问题发生，一条对应恢复。两条记录都显示 <code>Failed</code>，错误文本为：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>No message defined for media type.</span></span></code></pre></div><p>这说明 Action 条件已经匹配，通知动作也被创建了，但媒介或消息模板没有配置完整。故障现场遇到&quot;Problems 有事件但没收到通知&quot;时，可以按下面顺序查：</p><ol><li>Problems 页面是否真的生成事件。</li><li>事件标签、级别、主机组是否符合 Action 条件。</li><li>Action 是否 Enabled。</li><li>Operation 和 Recovery operation 是否都配置了接收人。</li><li>用户是否绑定了可用 Media。</li><li>Media type 是否启用，消息内容或脚本参数是否完整。</li><li>Action log 里是否有 Failed 和具体错误原因。</li></ol><h2 id="八、常见断点" tabindex="-1">八、常见断点 <a class="header-anchor" href="#八、常见断点" aria-label="Permalink to &quot;八、常见断点&quot;">​</a></h2><p>Zabbix 平台操作排错时，经常不是一个页面能看完。比较稳的检查路径如下：</p><table tabindex="0"><thead><tr><th>现象</th><th>优先位置</th><th>常见原因</th><th>修复方向</th></tr></thead><tbody><tr><td>主机 <code>ZBX</code> 不绿</td><td>Hosts / <code>zabbix_get</code></td><td>Agent 未启动、10050 不通、<code>Server=</code> 不允许</td><td>启动 Agent、放通防火墙、修正 Agent 配置</td></tr><tr><td>Latest data 没值</td><td>Latest data / Items</td><td>没绑定模板、Item disabled、更新间隔未到</td><td>绑定模板、启用 Item、等待或 Execute now</td></tr><tr><td>自定义 key Not supported</td><td>Latest data / Item Info</td><td><code>UserParameter</code> 不存在、配置文件未加载、脚本无权限</td><td>修正 Agent 配置、重启 Agent、用 <code>zabbix_get</code> 验证</td></tr><tr><td>Dashboard 没图</td><td>Dashboard / Graph</td><td>Item 没数据、图形绑定错 Item、时间范围不对</td><td>回 Latest data 确认值，再检查 Graph 或 Widget</td></tr><tr><td>Trigger 不出事件</td><td>Triggers / Problems</td><td>表达式写错、值类型不匹配、条件没有达到</td><td>看 Latest value，再对照表达式函数</td></tr><tr><td>有事件没通知</td><td>Action log</td><td>Action 条件不匹配、用户 Media 缺失、Media type 配置错误</td><td>查 Action 条件、用户媒介、Action log 错误</td></tr></tbody></table><p>平台上能看到红色状态时，信息还不够完整。还要补上错误原因：Item 的 Info、Problem 的详情、Action log 的 Failed 原因、Server 和 Agent 日志。Zabbix 的页面层级比较多，排错时把&quot;配置对象、数据结果、错误入口&quot;三类证据放在一起，后续复盘才不会只剩一个红色状态截图。</p>',130)])])}const u=e(h,[["render",b]]);export{x as __pageData,u as default};
